public void testSetMaxCodeLength_test5_decomposed()  {
    final String value = "jumped";
    final DoubleMetaphone doubleMetaphone = new DoubleMetaphone();
    assertEquals("Default Max Code Length", 4, doubleMetaphone.getMaxCodeLen());
