public void validateFixture(final String[][] pairs) {
    if (pairs.length == 0) {
        fail("Test fixture is empty");
    }
    for (int i = 0; i < pairs.length; i++) {
        if (pairs[i].length != 2) {
            fail("Error in test fixture in the data array at index " + i);
        }
    }
}

public void doubleMetaphoneNotEqualTest(final boolean alternate) {
    assertFalse(this.getStringEncoder().isDoubleMetaphoneEqual1("Brain", "Band", alternate));
    assertFalse(this.getStringEncoder().isDoubleMetaphoneEqual1("Band", "Brain", alternate));

    if (!alternate) {
        assertFalse(this.getStringEncoder().isDoubleMetaphoneEqual0("Brain", "Band"));
        assertFalse(this.getStringEncoder().isDoubleMetaphoneEqual0("Band", "Brain"));
    }
}

public void doubleMetaphoneEqualTest(final String[][] pairs, final boolean useAlternate) {
    this.validateFixture(pairs);
    for (final String[] pair : pairs) {
        final String name0 = pair[0];
        final String name1 = pair[1];
        final String failMsg =
                "Expected match between "
                        + name0
                        + " and "
                        + name1
                        + " (use alternate: "
                        + useAlternate
                        + ")";
        assertTrue(
                failMsg,
                this.getStringEncoder().isDoubleMetaphoneEqual1(name0, name1, useAlternate));
        assertTrue(
                failMsg,
                this.getStringEncoder().isDoubleMetaphoneEqual1(name1, name0, useAlternate));
        if (!useAlternate) {
            assertTrue(failMsg, this.getStringEncoder().isDoubleMetaphoneEqual0(name0, name1));
            assertTrue(failMsg, this.getStringEncoder().isDoubleMetaphoneEqual0(name1, name0));
        }
    }
}

public void assertDoubleMetaphoneAlt(final String expected, final String source) {
    assertEquals(expected, this.getStringEncoder().doubleMetaphone1(source, true));
}

private void assertDoubleMetaphone(final String expected, final String source) {
    assertEquals(expected, this.getStringEncoder().encode1(source));
    try {
        assertEquals(expected, this.getStringEncoder().encode0((Object) source));
    } catch (final EncoderException e) {
        fail("Unexpected expection: " + e);
    }
    assertEquals(expected, this.getStringEncoder().doubleMetaphone0(source));
    assertEquals(expected, this.getStringEncoder().doubleMetaphone1(source, false));
}
